from django import template
from blog.models import Article

register = template.Library()

@register.simple_tag
def total_articles():
    """Return the total count of published articles."""
    return Article.objects.filter(is_published=True).count()

@register.simple_tag(takes_context=True)
def user_article_count(context):
    """Return the number of articles by the current user."""
    user = context['request'].user
    if user.is_authenticated:
        return Article.objects.filter(author=user).count()
    return 0

# In template:
# {% load blog_extras %}
# <p>Total articles: {% total_articles %}</p>
# <p>Your articles: {% user_article_count %}</p>
# {% total_articles as count %}
# <p>We have {{ count }} articles.</p>

