from django import template
from blog.models import Article, Category

register = template.Library()

@register.inclusion_tag('blog/_recent_posts.html')
def recent_posts(count=5):
    """Render a list of recent posts."""
    posts = Article.objects.filter(
        is_published=True
    ).order_by('-published_at')[:count]
    return {'posts': posts}

@register.inclusion_tag('blog/_categories.html', takes_context=True)
def category_list(context):
    """Render the category sidebar with active highlighting."""
    current_category = context.get('current_category')
    categories = Category.objects.all()
    return {
        'categories': categories,
        'current_category': current_category,
    }

# blog/templates/blog/_recent_posts.html
